@rendermode InteractiveServer

<div class="drop-zone @(_isDragOver ? "drop-zone--drag-over" : "")"
     @ondragenter="HandleDragEnter"
     @ondragenter:preventDefault
     @ondragleave="HandleDragLeave"
     @ondragover:preventDefault
     @ondrop="HandleDrop"
     @ondrop:preventDefault>
    <InputFile @ref="_inputFileRef"
               OnChange="HandleFilesChanged"
               multiple
               class="drop-zone__input" />
    <p class="drop-zone__prompt">Drag &amp; drop files here, or click to browse</p>
</div>

@if (_entries.Count > 0)
{
    <ul class="drop-zone-file-list">
        @foreach (var entry in _entries)
        {
            <li class="drop-zone-file-list__item @(entry.Error is not null ? "drop-zone-file-list__item--error" : "")">
                <div class="drop-zone-file-list__details">
                    @if (entry.Error is not null)
                    {
                        <span class="drop-zone-file-list__name">@entry.Info.Name</span>
                        <span class="drop-zone-file-list__error">@entry.Error</span>
                    }
                    else
                    {
                        <span class="drop-zone-file-list__name">@entry.Info.Name</span>
                        <span class="drop-zone-file-list__meta">@FormatSize(entry.Info.Size) &middot; @entry.Info.Type</span>
                    }
                </div>
                <button class="drop-zone-file-list__remove" @onclick="() => Remove(entry)">Remove</button>
            </li>
        }
    </ul>
}

@code {
    private const long MaxFileSizeBytes = 10L * 1024 * 1024;

    private InputFile? _inputFileRef;
    private bool _isDragOver;
    private readonly List<FileEntry> _entries = new();

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    private void HandleDragEnter() => _isDragOver = true;
    private void HandleDragLeave() => _isDragOver = false;

    private async Task HandleDrop(DragEventArgs args)
    {
        _isDragOver = false;
        // Actual file data arrives via InputFile's OnChange; the drop is handled by the browser.
        await Task.CompletedTask;
    }

    private async Task HandleFilesChanged(InputFileChangeEventArgs e)
    {
        foreach (var file in e.GetMultipleFiles(maximumFileCount: 100))
        {
            var info = new FileInfo(file.Name, file.Size, file.ContentType);
            string? error = file.Size > MaxFileSizeBytes
                ? $"File exceeds the 10 MB limit ({FormatSize(file.Size)})"
                : null;

            _entries.Add(new FileEntry(info, error));
        }

        await NotifyParent();
    }

    private async Task Remove(FileEntry entry)
    {
        _entries.Remove(entry);
        await NotifyParent();
    }

    private async Task NotifyParent()
    {
        var accepted = _entries
            .Where(e => e.Error is null)
            .Select(e => e.Info)
            .ToList();

        await OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes) => bytes switch
    {
        < 1024 => $"{bytes} B",
        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
        _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
    };

    public record FileInfo(string Name, long Size, string Type);
    private record FileEntry(FileInfo Info, string? Error);
}

.drop-zone {
    position: relative;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 180px;
    border: 2px dashed #90a4ae;
    border-radius: 12px;
    background-color: #f5f7fa;
    transition: background-color 0.2s, border-color 0.2s;
    cursor: pointer;
}

.drop-zone--drag-over {
    background-color: #e3f2fd;
    border-color: #1976d2;
}

.drop-zone__prompt {
    color: #607d8b;
    font-size: 1rem;
    pointer-events: none;
}

.drop-zone__input {
    position: absolute;
    inset: 0;
    opacity: 0;
    cursor: pointer;
}

/* File list */
.drop-zone-file-list {
    list-style: none;
    margin: 1rem 0 0;
    padding: 0;
}

.drop-zone-file-list__item {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.5rem 0.75rem;
    border: 1px solid #e0e0e0;
    border-radius: 6px;
    margin-bottom: 0.5rem;
    background: #fff;
}

.drop-zone-file-list__item--error {
    border-color: #e53935;
    background: #ffebee;
}

.drop-zone-file-list__details {
    display: flex;
    flex-direction: column;
    gap: 0.15rem;
    overflow: hidden;
}

.drop-zone-file-list__name {
    font-weight: 600;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.drop-zone-file-list__meta {
    font-size: 0.85rem;
    color: #757575;
}

.drop-zone-file-list__error {
    font-size: 0.85rem;
    color: #e53935;
    font-weight: 500;
}

.drop-zone-file-list__remove {
    flex-shrink: 0;
    margin-left: 1rem;
    padding: 0.25rem 0.6rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    background: #fafafa;
    cursor: pointer;
    font-size: 0.85rem;
}

.drop-zone-file-list__remove:hover {
    background: #eee;
}

