toolArgs.file_text:
.drop-zone {
    position: relative;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 180px;
    border: 2px dashed #90a4ae;
    border-radius: 12px;
    background-color: #f5f7fa;
    transition: background-color 0.2s, border-color 0.2s;
    cursor: pointer;
}

.drop-zone--drag-over {
    background-color: #e3f2fd;
    border-color: #1976d2;
}

.drop-zone__prompt {
    color: #607d8b;
    font-size: 1rem;
    pointer-events: none;
}

.drop-zone__input {
    position: absolute;
    inset: 0;
    opacity: 0;
    cursor: pointer;
}

/* File list */
.drop-zone-file-list {
    list-style: none;
    margin: 1rem 0 0;
    padding: 0;
}

.drop-zone-file-list__item {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.5rem 0.75rem;
    border: 1px solid #e0e0e0;
    border-radius: 6px;
    margin-bottom: 0.5rem;
    background: #fff;
}

.drop-zone-file-list__item--error {
    border-color: #e53935;
    background: #ffebee;
}

.drop-zone-file-list__details {
    display: flex;
    flex-direction: column;
    gap: 0.15rem;
    overflow: hidden;
}

.drop-zone-file-list__name {
    font-weight: 600;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.drop-zone-file-list__meta {
    font-size: 0.85rem;
    color: #757575;
}

.drop-zone-file-list__error {
    font-size: 0.85rem;
    color: #e53935;
    font-weight: 500;
}

.drop-zone-file-list__remove {
    flex-shrink: 0;
    margin-left: 1rem;
    padding: 0.25rem 0.6rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    background: #fafafa;
    cursor: pointer;
    font-size: 0.85rem;
}

.drop-zone-file-list__remove:hover {
    background: #eee;
}

